function navigateToPage(pageId) {
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active-page'));
    document.getElementById(pageId).classList.add('active-page');
    window.scrollTo(0, 0);
}

function handleLogin(e) {
    e.preventDefault();
    const user = document.getElementById('username').value.trim().toLowerCase();
    const pass = document.getElementById('password').value;

    if (!user || !pass) {
        document.getElementById('login-error').innerText = 'Username dan password wajib diisi.';
        document.getElementById('login-error').style.display = 'block';
        return;
    }

    if (!STUDENT_ACCOUNTS[user] || STUDENT_ACCOUNTS[user] !== pass) {
        document.getElementById('login-error').innerText = 'Username atau password salah.';
        document.getElementById('login-error').style.display = 'block';
        return;
    }

    currentUser = user;
    document.getElementById('profile-username').innerText = user;
    document.getElementById('login-error').style.display = 'none';

    const savedData = localStorage.getItem(`RIWAYAT_TRYOUT_${currentUser}`);
    RIWAYAT_USER_LOKAL = savedData ? JSON.parse(savedData) : {};

    navigateToPage('page-dashboard');
    renderDashboardStatus();
}

