function renderDashboardStatus() {
    const listPaket = ['skd1', 'skd2', 'skd3', 'skd4','skd5','skdprem'];
    listPaket.forEach(id => {
        const btn = document.getElementById(`btn-${id}`);
        const card = document.getElementById(`card-${id}`);
        if (!btn) return;

        if (RIWAYAT_USER_LOKAL[id]) {
            if (card) card.style.borderLeft = "6px solid #2b7a5e";
            btn.innerHTML = "Hasil Try Out &rarr;";
            btn.className = "btn btn-review";
        } else {
            if (card) card.style.borderLeft = "1px solid #ddd";
            btn.innerHTML = "Pilih Paket &rarr;";
            btn.className = "btn";
        }
    });
}

