function startCountdownAnimation() {
    navigateToPage('countdown-screen');
    document.getElementById('countdown-screen').style.display = 'flex';
    let count = 3;
    document.getElementById('countdown-number').innerText = count;

    let interval = setInterval(() => {
        count--;
        if (count > 0) {
            document.getElementById('countdown-number').innerText = count;
        } else {
            clearInterval(interval);
            document.getElementById('countdown-screen').style.display = 'none';
            mulaiUjianSistem();
        }
    }, 1000);
}

function mulaiUjianSistem() {
    currentSoalIndex = 0;
    jawabanUser = {};
    raguRaguStatus = {};
    sisaWaktuDetik = DURASI_UJIAN_DETIK;

    document.getElementById('exam-package-name').innerText = "Tryout " + currentPaketId.toUpperCase();

    buildNavigationGrid();
    showSoalByIndex(currentSoalIndex);

    clearInterval(timerInterval);
    startTimerCountdown();

    navigateToPage('page-exam');
}

function startTimerCountdown() {
    timerInterval = setInterval(() => {
        if (sisaWaktuDetik <= 0) {
            clearInterval(timerInterval);
            autoSubmitUjian();
        } else {
            sisaWaktuDetik--;
            let min = Math.floor(sisaWaktuDetik / 60);
            let sec = sisaWaktuDetik % 60;
            document.getElementById('timer-display').innerText =
                (min < 10 ? '0' + min : min) + ':' + (sec < 10 ? '0' + sec : sec);
        }
    }, 1000);
}

function getOptionText(soal, key) {
    const option = soal.options[key];
    if (typeof option === 'string') return option;
    if (option && typeof option === 'object') {
        return option.text || option.label || option.teks || '';
    }
    return '';
}

function getOptionImage(soal, key) {
    const option = soal.options[key];
    if (option && typeof option === 'object') {
        return option.gambar || option.image || option.img || '';
    }
    return '';
}

function escapeHtml(value) {
    return String(value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

function renderMathText(value) {
    if (value == null) return '';
    const escaped = escapeHtml(value);
    return escaped.replace(/\r\n|\r|\n/g, '<br>');
}

function typesetMath(elements = []) {
    if (window.MathJax && typeof MathJax.typesetPromise === 'function') {
        MathJax.typesetPromise(elements).catch((err) => console.error('MathJax typeset error', err));
    }
}

function buildNavigationGrid() {
    const gridTwk = document.getElementById('grid-twk');
    const gridTiu = document.getElementById('grid-tiu');
    const gridTkp = document.getElementById('grid-tkp');

    if (!gridTwk || !gridTiu || !gridTkp) return;
    gridTwk.innerHTML = "";
    gridTiu.innerHTML = "";
    gridTkp.innerHTML = "";

    listSoalAktif.forEach((soal, index) => {
        const box = document.createElement('div');
        box.className = 'nav-num';
        box.innerText = index + 1;
        box.id = `nav-box-${index}`;
        box.onclick = () => jumpToSoal(index);

        if (soal.category === 'twk') gridTwk.appendChild(box);
        else if (soal.category === 'tiu') gridTiu.appendChild(box);
        else if (soal.category === 'tkp') gridTkp.appendChild(box);
    });
}

function updateNavigationClass(index) {
    const box = document.getElementById(`nav-box-${index}`);
    if (!box) return;

    box.classList.remove('active', 'answered', 'ragu');

    if (index === currentSoalIndex) {
        box.classList.add('active');
    }
    if (raguRaguStatus[index]) {
        box.classList.add('ragu');
    } else if (jawabanUser[index]) {
        box.classList.add('answered');
    }
}

function syncAllNavigationStates() {
    listSoalAktif.forEach((_, idx) => updateNavigationClass(idx));
}

function showSoalByIndex(index) {
    currentSoalIndex = index;
    const soal = listSoalAktif[index];
    if (!soal) return;

    document.getElementById('soal-category-badge').innerText = soal.category.toUpperCase();
    document.getElementById('soal-number-title').innerText = `Soal No. ${index + 1}`;
    document.getElementById('soal-text').innerHTML = renderMathText(soal.question || 'Perhatikan gambar berikut.');

    const oldImg = document.getElementById('exam-soal-img');
    if (oldImg) oldImg.remove();

    const soalImage = soal.gambar || soal.image || '';
    if (soalImage) {
        const imgTag = document.createElement('img');
        imgTag.src = soalImage;
        imgTag.id = 'exam-soal-img';
        imgTag.className = 'soal-img';
        imgTag.alt = 'Gambar Soal';
        document.getElementById('soal-text').after(imgTag);
    }

    const optBlock = document.getElementById('options-block');
    optBlock.innerHTML = "";

    Object.keys(soal.options).forEach(key => {
        const item = document.createElement('div');
        item.className = 'option-item';

        const radio = document.createElement('input');
        radio.type = 'radio';
        radio.name = 'option_choice';
        radio.value = key;
        if (jawabanUser[index] === key) radio.checked = true;

        radio.onchange = () => pilihJawabanSistem(index, key);
        item.onclick = () => { radio.checked = true; pilihJawabanSistem(index, key); };

        const textWrapper = document.createElement('div');
        textWrapper.className = 'option-text-wrapper';

        const label = document.createElement('span');
        const optionText = getOptionText(soal, key);
        label.innerHTML = `${key}. ${renderMathText(optionText || 'Pilih jawaban')}`;
        textWrapper.appendChild(label);

        const optionImage = getOptionImage(soal, key);
        if (optionImage) {
            const optImg = document.createElement('img');
            optImg.src = optionImage;
            optImg.className = 'option-img';
            optImg.alt = `Gambar Pilihan ${key}`;
            textWrapper.appendChild(optImg);
        }

        item.appendChild(radio);
        item.appendChild(textWrapper);
        optBlock.appendChild(item);
    });

    const btnRagu = document.getElementById('btn-ragu');
    if (btnRagu) {
        if (raguRaguStatus[index]) {
            btnRagu.style.backgroundColor = "#ffb703";
            btnRagu.innerText = "Ragu-Ragu (Aktif)";
        } else {
            btnRagu.style.backgroundColor = "var(--yellow-ragu)";
            btnRagu.innerText = "Ragu-Ragu";
        }
    }

    syncAllNavigationStates();
    typesetMath([document.getElementById('soal-text'), optBlock]);
}

function pilihJawabanSistem(index, pilihan) {
    jawabanUser[index] = pilihan;
    updateNavigationClass(index);
}

function toggleRaguRagu() {
    raguRaguStatus[currentSoalIndex] = !raguRaguStatus[currentSoalIndex];
    showSoalByIndex(currentSoalIndex);
}

function prevSoal() {
    if (currentSoalIndex > 0) {
        showSoalByIndex(currentSoalIndex - 1);
    }
}

function nextSoal() {
    if (currentSoalIndex < listSoalAktif.length - 1) {
        showSoalByIndex(currentSoalIndex + 1);
    }
}

function jumpToSoal(index) {
    showSoalByIndex(index);
}

function confirmSubmitUjian() {
    if (confirm("Apakah Anda yakin ingin mengakhiri tryout ini?")) {
        clearInterval(timerInterval);
        hitungDanTampilkanHasil(true);
    }
}

function autoSubmitUjian() {
    alert("Waktu pengerjaan telah habis! Sistem otomatis mengumpulkan jawaban Anda.");
    hitungDanTampilkanHasil(true);
}

function hitungDanTampilkanHasil(isNewSubmission = true) {
    let totalBenar = 0;
    let totalSalah = 0;
    let totalKosong = 0;

    let skorTWK = 0, benarTWK = 0, salahTWK = 0, kosongTWK = 0;
    let skorTIU = 0, benarTIU = 0, salahTIU = 0, kosongTIU = 0;
    let skorTKP = 0, answeredTKP = 0, kosongTKP = 0;

    let reviewHTML = { twk: "", tiu: "", tkp: "" };

    listSoalAktif.forEach((soal, index) => {
        const userAns = jawabanUser[index];
        let poinSoal = 0;
        let statusIcon = "";

        if (!userAns) {
            totalKosong++;
            poinSoal = 0;
            statusIcon = `<span style="color: #666; font-weight: bold;">⚪ Tidak Diisi (Skor: 0)</span>`;

            if (soal.category === 'twk') kosongTWK++;
            else if (soal.category === 'tiu') kosongTIU++;
            else if (soal.category === 'tkp') kosongTKP++;
        } else {
            if (soal.category === 'twk') {
                if (userAns === soal.answer) {
                    skorTWK += 5; benarTWK++; totalBenar++; poinSoal = 5;
                    statusIcon = `<span style="color: #2b7a5e; font-weight: bold;">✔️ Benar (Skor: 5)</span>`;
                } else {
                    salahTWK++; totalSalah++; poinSoal = 0;
                    statusIcon = `<span style="color: #d90429; font-weight: bold;">❌ Salah (Skor: 0)</span>`;
                }
            } else if (soal.category === 'tiu') {
                if (userAns === soal.answer) {
                    skorTIU += 5; benarTIU++; totalBenar++; poinSoal = 5;
                    statusIcon = `<span style="color: #2b7a5e; font-weight: bold;">✔️ Benar (Skor: 5)</span>`;
                } else {
                    salahTIU++; totalSalah++; poinSoal = 0;
                    statusIcon = `<span style="color: #d90429; font-weight: bold;">❌ Salah (Skor: 0)</span>`;
                }
            } else if (soal.category === 'tkp') {
                answeredTKP++;
                if (soal.points && soal.points[userAns] !== undefined) {
                    poinSoal = soal.points[userAns];
                } else {
                    poinSoal = (userAns === soal.answer) ? 5 : 1;
                }

                skorTKP += poinSoal;
                if (poinSoal === 5) totalBenar++; else totalSalah++;
                statusIcon = `<span style="color: #b57c00; font-weight: bold;">📝 Terjawab (Skor: ${poinSoal})</span>`;
            }
        }

        let opsiHTML = "";
        Object.keys(soal.options).forEach(key => {
            const optionText = getOptionText(soal, key);
            const isKeyAnswer = soal.category !== 'tkp'
                ? key === soal.answer
                : soal.points && soal.points[key] === 5;
            const isSelectedOption = userAns === key;
            const optionClass = isKeyAnswer
                ? ' correct'
                : isSelectedOption
                    ? ' selected'
                    : '';
            let teksPoinTKP = "";

            if (soal.category === 'tkp' && soal.points && soal.points[key] !== undefined) {
                teksPoinTKP = ` <span class="option-point">[Poin: ${soal.points[key]}]</span>`;
            }

            opsiHTML += `<div class="review-option-item${optionClass}${isSelectedOption && !isKeyAnswer ? ' incorrect' : ''}">
                    ${key}. ${renderMathText(optionText || 'Pilih jawaban')}${teksPoinTKP}
                </div>`;
        });

        let infoKunciTambahan = (soal.category === 'tkp') ? `Skor 5 di Opsi: <strong style="color:green;">${Object.keys(soal.points || {}).find(k => soal.points[k] === 5) || soal.answer}</strong>` : `Kunci Utama: <strong style="color:green;">${soal.answer}</strong>`;
        const questionHtml = renderMathText(soal.question);

        reviewHTML[soal.category] += `
            <div class="review-question-card">
                <div class="review-question-header">
                    <div class="review-question-number">Soal No. ${index + 1}</div>
                    <div class="review-status">${statusIcon}</div>
                </div>
                <div class="review-question-text">${questionHtml}</div>
                <div class="review-options">${opsiHTML}</div>
                <p class="review-answer-info">
                    👉 Jawaban Anda: <strong>${userAns || '-'}</strong> | ${infoKunciTambahan}
                </p>
            </div>
        `;
    });

    const totalSkorAkhir = skorTWK + skorTIU + skorTKP;

    document.getElementById('final-score').innerText = totalSkorAkhir;
    document.getElementById('stat-count-benar').innerText = totalBenar;
    document.getElementById('stat-count-salah').innerText = totalSalah;
    document.getElementById('stat-count-kosong').innerText = totalKosong;
    document.getElementById('result-package-label').innerText = `Hasil Evaluasi • Tryout ${currentPaketId.toUpperCase()}`;

    const circle = document.getElementById('circle-score-radial');
    if (circle) {
        const percent = (totalSkorAkhir / 550) * 100;
        circle.style.background = `conic-gradient(var(--pink-primary) ${percent}%, var(--pink-bg) ${percent}%)`;
    }

    const analysisContainer = document.getElementById('analysis-container');
    if (analysisContainer) {
        analysisContainer.innerHTML = `
            <div class="analysis-section">
                <details open>
                    <summary class="analysis-summary">
                        <div class="analysis-summary-left">
                            <span class="analysis-category">📌 TES WAWASAN KEBANGSAAN (TWK)</span>
                            <span class="analysis-subtitle">Ringkasan pengerjaan & pembahasan</span>
                        </div>
                        <div class="analysis-summary-right">
                            <span class="analysis-badges"><span class="badge-score">${skorTWK}</span> / 150</span>
                        </div>
                    </summary>
                    <div class="analysis-detail-content">
                        <div class="analysis-summary-grid">
                            <div><strong>Jawaban Benar</strong>${benarTWK} soal</div>
                            <div><strong>Jawaban Salah</strong>${salahTWK} soal</div>
                            <div><strong>Tidak Diisi</strong>${kosongTWK} soal</div>
                        </div>
                        <div class="analysis-subsection">
                            <div class="analysis-subsection-title">Pembahasan Soal TWK</div>
                            <div class="review-list">${reviewHTML.twk}</div>
                        </div>
                    </div>
                </details>
            </div>
            <div class="analysis-section">
                <details open>
                    <summary class="analysis-summary">
                        <div class="analysis-summary-left">
                            <span class="analysis-category">📊 TES INTELIGENSIA UMUM (TIU)</span>
                            <span class="analysis-subtitle">Ringkasan pengerjaan & pembahasan</span>
                        </div>
                        <div class="analysis-summary-right">
                            <span class="analysis-badges"><span class="badge-score">${skorTIU}</span> / 175</span>
                        </div>
                    </summary>
                    <div class="analysis-detail-content">
                        <div class="analysis-summary-grid">
                            <div><strong>Jawaban Benar</strong>${benarTIU} soal</div>
                            <div><strong>Jawaban Salah</strong>${salahTIU} soal</div>
                            <div><strong>Tidak Diisi</strong>${kosongTIU} soal</div>
                        </div>
                        <div class="analysis-subsection">
                            <div class="analysis-subsection-title">Pembahasan Soal TIU</div>
                            <div class="review-list">${reviewHTML.tiu}</div>
                        </div>
                    </div>
                </details>
            </div>
            <div class="analysis-section">
                <details open>
                    <summary class="analysis-summary">
                        <div class="analysis-summary-left">
                            <span class="analysis-category">🧠 TES KARAKTERISTIK PRIBADI (TKP)</span>
                            <span class="analysis-subtitle">Ringkasan pengerjaan & pembahasan</span>
                        </div>
                        <div class="analysis-summary-right">
                            <span class="analysis-badges"><span class="badge-score">${skorTKP}</span> / 225</span>
                        </div>
                    </summary>
                    <div class="analysis-detail-content">
                        <div class="analysis-summary-grid">
                            <div><strong>Terjawab</strong>${answeredTKP} soal</div>
                            <div><strong>Tidak Diisi</strong>${kosongTKP} soal</div>
                        </div>
                        <div class="analysis-subsection">
                            <div class="analysis-subsection-title">Pembahasan Soal TKP</div>
                            <div class="review-list">${reviewHTML.tkp}</div>
                        </div>
                    </div>
                </details>
            </div>
        `;
        typesetMath([analysisContainer]);
    }

    if (isNewSubmission) {
        RIWAYAT_USER_LOKAL[currentPaketId] = {
            skor_total: totalSkorAkhir,
            jawaban: jawabanUser
        };
        localStorage.setItem(`RIWAYAT_TRYOUT_${currentUser}`, JSON.stringify(RIWAYAT_USER_LOKAL));
        kirimDataKeGoogleSheets(totalSkorAkhir, skorTWK, skorTIU, skorTKP);
    }

    navigateToPage('page-result');
}

function kirimDataKeGoogleSheets(totalSkor, twk, tiu, tkp) {
    const toast = document.getElementById('sync-toast');
    if (toast) {
        toast.style.backgroundColor = "#eefcf7";
        toast.style.color = "#2b7a5e";
        toast.innerText = "🔄 Mengirim hasil ujian ke server...";
    }

    const formData = new URLSearchParams();
    formData.append('username', currentUser || "User_Kosong");
    formData.append('paket', (currentPaketId || "SKD").toUpperCase());
    formData.append('skor_twk', twk ?? 0);
    formData.append('skor_tiu', tiu ?? 0);
    formData.append('skor_tkp', tkp ?? 0);
    formData.append('skor_total', totalSkor ?? 0);
    formData.append('timestamp', new Date().toLocaleString('id-ID'));

    fetch(urlGoogleScript, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: formData.toString()
    })
    .then(() => {
        if (toast) {
            toast.innerText = "✅ Data berhasil disinkronisasi ke Cloud Server!";
            toast.style.backgroundColor = "#eefcf7";
            toast.style.color = "#2b7a5e";
        }
    })
    .catch(err => {
        console.error("Error Pengiriman:", err);
        if (toast) {
            toast.innerText = "❌ Gagal sinkronisasi data cloud.";
            toast.style.backgroundColor = "#ffebeb";
            toast.style.color = "#d90429";
        }
    });
}